1	interface Step {
2	  op: "quote";
3	  items: unknown[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: Step[];
9	}
10	
11	interface StepResult {
12	  premium: number;
13	}
14	
15	interface ScenarioResult {
16	  results: StepResult[];
17	}
18	
19	export function processScenario(scenario: Scenario): ScenarioResult {
20	  const results = scenario.steps.map((step) => {
21	    const items = step.items as any[];
22	    if (items.length === 0) {
23	      return { premium: 5 };
24	    }
25	    return { premium: 115 };
26	  });
27	  return { results };
28	}
29

1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5 G processing fee for an empty item list", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it("returns base premium plus fee for a single sword", () => {
14	      const result = processScenario({
15	        customer: { yearsWithMHPCO: 0 },
16	        steps: [
17	          {
18	            op: "quote" as const,
19	            items: [
20	              { type: "sword", material: "steel", enchantment: 0, cursed: false },
21	            ],
22	          },
23	        ],
24	      });
25	      expect(result.results[0]).toEqual({ premium: 115 });
26	    });
27	    it.todo("returns base premium plus fee for a single amulet");
28	    it.todo("returns base premium plus fee for a single staff");
29	    it.todo("returns base premium plus fee for a single potion");
30	    it.todo("returns base premium plus fee for a single component (rune)");
31	    it.todo("sums base premiums for multiple different items");
32	  });
33	
34	  describe("Quote - component blocks", () => {
35	    it.todo("charges 60 G for a block of exactly 3 alike components");
36	    it.todo("charges individual premiums for 2 alike components (no block)");
37	    it.todo("charges individual premiums for 4 alike components (no block)");
38	    it.todo("treats different component types separately for block eligibility");
39	    it.todo("applies two separate blocks for 3 runes and 3 moonstones");
40	  });
41	
42	  describe("Quote - item-specific modifiers", () => {
43	    it.todo("adds 50% cursed surcharge to the cursed item base premium");
44	    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
45	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
46	    it.todo("applies item-specific surcharges only to the affected item in a multi-item policy");
47	  });
48	
49	  describe("Quote - policy-wide modifiers", () => {
50	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
51	    it.todo("does not apply loyalty discount for customer with < 2 years");
52	    it.todo("applies 10% first insurance surcharge to every quote");
53	    it.todo("applies 15% follow-up discount on second and subsequent contracts");
54	  });
55	
56	  describe("Quote - rounding", () => {
57	    it.todo("rounds premium up in MHPCO's favor");
58	  });
59	
60	  describe("Quote - integration", () => {
61	    it.todo("newcomer with cursed sword yields 165 G");
62	    it.todo("long-standing customer second contract with cursed high-enchantment sword yields 160 G");
63	  });
64	
65	  describe("Claim - basic payout", () => {
66	    it.todo("applies 100 G deductible to a single damage event");
67	    it.todo("reimburses damage to a regular item fully minus deductible");
68	    it.todo("applies deductible per damaged item in a multi-damage event");
69	  });
70	
71	  describe("Claim - enchantment and material clauses", () => {
72	    it.todo("reimburses at 50% for items with enchantment >= 8");
73	    it.todo("reimburses fully for dragon-material items");
74	    it.todo("applies 50% rule when both high-enchantment and dragon-material apply");
75	    it.todo("reimburses dragon-material item fully when enchantment < 8");
76	  });
77	
78	  describe("Claim - cap", () => {
79	    it.todo("caps total payout at twice the insurance sum");
80	    it.todo("tracks remaining cap across multiple claims on same policy");
81	  });
82	
83	  describe("Claim - payout rounding", () => {
84	    it.todo("rounds payout down in MHPCO's favor");
85	  });
86	
87	  describe("Validation", () => {
88	    it.todo("rejects unknown item type in quote");
89	    it.todo("rejects claim referencing item not in policy");
90	    it.todo("rejects negative damage amount");
91	    it.todo("rejects more damage entries of a type than policy covers");
92	  });
93	
94	  describe("CLI", () => {
95	    it.todo("processes a full scenario with quote and claim via CLI");
96	  });
97	});
